You are modifying the clui Rust rewrite to use the `claude` CLI subprocess instead of calling the Anthropic HTTP API directly. The user has a Claude subscription but not a separate API key.

**Repo:** `/Users/4thwithme/Documents/repo/clui`
**Rust workspace:** `/Users/4thwithme/Documents/repo/clui/rust/`
**Run first:** `source "$HOME/.cargo/env"`

## Background

The `claude` CLI (Claude Code) is installed at something like `/Users/4thwithme/.claude/local/claude` or in PATH. It supports:
```bash
claude --print "your prompt" --output-format stream-json
claude --print "follow-up" --output-format stream-json --resume <session_id>
```

With `--output-format stream-json` it outputs newline-delimited JSON events:
- `{"type":"system","subtype":"init","session_id":"abc123",...}` — first line, gives session ID
- `{"type":"assistant","message":{"content":[{"type":"text","text":"Hello!"}],"usage":{"input_tokens":10,"output_tokens":5}},"session_id":"abc123"}`
- `{"type":"result","subtype":"success","result":"Hello!","session_id":"abc123"}`

The `--resume session_id` flag continues an existing conversation session, enabling multi-turn context without manually managing message history.

---

## Step 1: Create `rust/crates/agent/src/cli_client.rs`

```rust
use anyhow::Result;
use serde::Deserialize;
use tokio::io::{AsyncBufReadExt, BufReader};
use tokio::process::Command;
use tokio::sync::mpsc;

use crate::client::AgentEvent;

#[derive(Debug, Clone)]
pub struct CliAgentClient {
    pub session_id: Option<String>,
    pub cwd: String,
    pub model: String,
}

#[derive(Debug, Deserialize)]
struct CliEvent {
    #[serde(rename = "type")]
    event_type: String,
    subtype: Option<String>,
    session_id: Option<String>,
    message: Option<CliMessage>,
}

#[derive(Debug, Deserialize)]
struct CliMessage {
    content: Option<Vec<CliContent>>,
    usage: Option<CliUsage>,
}

#[derive(Debug, Deserialize)]
struct CliContent {
    #[serde(rename = "type")]
    content_type: String,
    text: Option<String>,
}

#[derive(Debug, Deserialize)]
struct CliUsage {
    output_tokens: Option<u32>,
}

impl CliAgentClient {
    pub fn new(cwd: String, model: String) -> Self {
        Self {
            session_id: None,
            cwd,
            model,
        }
    }

    pub fn reset(&mut self) {
        self.session_id = None;
    }

    pub async fn send(
        &mut self,
        prompt: String,
        tx: mpsc::Sender<AgentEvent>,
    ) -> Result<()> {
        // Find claude binary — try PATH first, then known locations
        let claude_bin = find_claude_binary();

        let mut cmd = Command::new(&claude_bin);
        cmd.arg("--print")
            .arg(&prompt)
            .arg("--output-format")
            .arg("stream-json")
            .arg("--model")
            .arg(&self.model)
            .current_dir(&self.cwd)
            .stdout(std::process::Stdio::piped())
            .stderr(std::process::Stdio::piped());

        if let Some(ref sid) = self.session_id {
            cmd.arg("--resume").arg(sid);
        }

        let mut child = match cmd.spawn() {
            Ok(c) => c,
            Err(e) => {
                let _ = tx
                    .send(AgentEvent::Error(format!(
                        "Failed to spawn claude CLI ({}): {}. Is 'claude' in PATH?",
                        claude_bin, e
                    )))
                    .await;
                return Ok(());
            }
        };

        let stdout = child.stdout.take().expect("stdout not captured");
        let mut lines = BufReader::new(stdout).lines();

        let mut full_content = String::new();
        let mut output_tokens = 0u32;

        while let Some(line) = lines.next_line().await? {
            if line.is_empty() {
                continue;
            }

            let Ok(event) = serde_json::from_str::<CliEvent>(&line) else {
                continue;
            };

            match event.event_type.as_str() {
                "system" if event.subtype.as_deref() == Some("init") => {
                    if let Some(sid) = event.session_id {
                        self.session_id = Some(sid);
                    }
                }
                "assistant" => {
                    if let Some(msg) = event.message {
                        if let Some(usage) = &msg.usage {
                            output_tokens = usage.output_tokens.unwrap_or(0);
                        }
                        if let Some(content) = msg.content {
                            for item in content {
                                if item.content_type == "text" {
                                    if let Some(text) = item.text {
                                        full_content.push_str(&text);
                                        let _ = tx
                                            .send(AgentEvent::StreamChunk(text))
                                            .await;
                                    }
                                }
                            }
                        }
                    }
                }
                "result" => {
                    if event.subtype.as_deref() == Some("error") {
                        let _ = tx.send(AgentEvent::Error("claude CLI returned error".into())).await;
                    }
                    break;
                }
                _ => {}
            }
        }

        let _ = child.wait().await;
        let _ = tx
            .send(AgentEvent::MessageComplete {
                content: full_content,
                output_tokens,
            })
            .await;
        Ok(())
    }
}

fn find_claude_binary() -> String {
    // Try common locations
    let candidates = [
        "claude", // PATH
        "/Users/4thwithme/.claude/local/claude",
        "/usr/local/bin/claude",
    ];
    for candidate in &candidates {
        if std::path::Path::new(candidate).exists() || candidate == &"claude" {
            return candidate.to_string();
        }
    }
    "claude".to_string()
}
```

